import{_ as t,o,c as a,ae as i}from"./chunks/framework.B6gjLfeO.js";const h=JSON.parse('{"title":"Advanced Journeys Configuration","description":"","frontmatter":{"title":"Advanced Journeys Configuration","slug":"advanced-journeys-configuration"},"headers":[],"relativePath":"marketer-hub/advanced-journeys-configuration.md","filePath":"marketer-hub/advanced-journeys-configuration.md"}'),r={name:"marketer-hub/advanced-journeys-configuration.md"};function n(s,e,l,d,u,p){return o(),a("div",null,[...e[0]||(e[0]=[i('<h2 id="journeys-ios-safari-banner-compatibility" tabindex="-1">Journeys &amp; iOS Safari Banner Compatibility <a class="header-anchor" href="#journeys-ios-safari-banner-compatibility" aria-label="Permalink to &quot;Journeys &amp; iOS Safari Banner Compatibility&quot;">​</a></h2><p>If you have iOS Universal Links enabled on your main domain, you should see Apple&#39;s <a href="https://developer.apple.com/documentation/webkit/promoting_apps_with_smart_app_banners" target="_blank" rel="noreferrer">Smart App Banners</a> along with your Journeys banner. This can lead to customer confusion on which call to action to interact with to get to your mobile app.</p><p>In order to maximize conversion while maintaining full compatibility of Journeys and Universal Links, we recommend utilizing a <strong>Floating Pill Button</strong> for your Journeys campaign.</p><p><em>[Image: 882]</em></p><h2 id="journeys-website-redirect-options" tabindex="-1">Journeys Website Redirect Options <a class="header-anchor" href="#journeys-website-redirect-options" aria-label="Permalink to &quot;Journeys Website Redirect Options&quot;">​</a></h2><p>You can configure your Journeys banner to redirect users to a website by doing the following:</p><h4 id="configure-your-redirect-keys" tabindex="-1">Configure Your Redirect Keys <a class="header-anchor" href="#configure-your-redirect-keys" aria-label="Permalink to &quot;Configure Your Redirect Keys&quot;">​</a></h4><ul><li><p><code>$android_url</code> - Controls where the journey sends Android users who do not have the app installed; otherwise, the user will be deep linked into the app if installed.</p></li><li><p><code>$ios_url</code> - Controls where the journey sends iOS users who do not have the app installed; otherwise, the user will be deep linked into the app if installed.</p></li><li><p><code>$fallback_url</code> - Controls where the journey sends users who do not have the app installed; otherwise, the user will be deep linked into the app if installed.</p></li><li><p><code>$journeys_cta</code> - Controls where the journey link will redirect to.</p><ul><li><p>User is redirected to the provided location regardless of whether or not they have the app installed.</p><ul><li>For example, redirect all Journeys clicks to mobile web OR deep link users to a different app for cross-promotion.</li></ul></li><li><p>This key overrides all others.</p></li><li><p><strong>NOTE</strong>: Removes the ability to track Journeys click-through rates, as the customer&#39;s link will be used for the CTA. Branch will not get clicks, and thus it will not be able to attribute installs, opens, or conversion events.</p></li></ul></li></ul><h3 id="setup-via-dashboard" tabindex="-1">Setup via Dashboard <a class="header-anchor" href="#setup-via-dashboard" aria-label="Permalink to &quot;Setup via Dashboard&quot;">​</a></h3><p>When configuring your <a href="./create-journey-banner-or-interstitial.html#2-configure-creatives">Journeys Template</a>:</p><ul><li>On the <strong>VIEW EDITOR</strong> tab, click the CTA button in the UI of the template you&#39;ve chosen.</li><li>Add key-value pairs in the <strong>DEEP LINK DATA</strong> section.</li><li>Click <strong>Save&amp;Close</strong>.</li></ul><h2 id="dynamic-journeys-layout-customization" tabindex="-1">Dynamic Journeys Layout Customization <a class="header-anchor" href="#dynamic-journeys-layout-customization" aria-label="Permalink to &quot;Dynamic Journeys Layout Customization&quot;">​</a></h2><p>You can customize the appearance of a Journey depending on which link referred to the web session. So, you can create a Branch Link with a set of defined keys and values that will change properties such as the title or images when the user is referred to your website from this link.</p><table tabindex="0"><thead><tr><th><strong>Link Data Key</strong></th><th><strong>Value</strong></th><th><strong>Example Value</strong></th></tr></thead><tbody><tr><td><code>$journeys_button_get_has_app</code></td><td>The call to action button when the app is currently installed</td><td>&quot;Open App&quot;</td></tr><tr><td><code>$journeys_button_get_no_app</code></td><td>The call to action button when the app is <strong>not</strong> currently installed</td><td>&quot;Install App&quot;</td></tr><tr><td><code>$journeys_title</code></td><td>The title or main text of your Journey</td><td>&quot;Download Appsolutely today&quot;</td></tr><tr><td><code>$journeys_description</code></td><td>This is the description or subtitle in the frame</td><td>&quot;This app is disrupting apps&quot;</td></tr><tr><td><code>$journeys_icon_image_url</code></td><td>The app icon displayed in the layout</td><td>&quot;&amp;lt;<a href="https://mysite.com/image.png%5C&amp;gt;" target="_blank" rel="noreferrer">https://mysite.com/image.png\\&gt;</a>&quot;</td></tr></tbody></table><p>Note: Not all templates support all override keys. For example, the floating button does not support title, description, or icon image URL (Floating Pills will support the custom liquid tags detailed below). If a creative is to be rendered and the key you&#39;ve specified does not exist, it is ignored.</p><h2 id="custom-data" tabindex="-1">Custom Data <a class="header-anchor" href="#custom-data" aria-label="Permalink to &quot;Custom Data&quot;">​</a></h2><p>Send users into your app with a discount or promotional coupon code by adding deep link data to your Journey template. In the call-to-action editing step, assign your deep link data key value pairs. This could look something like:</p>',17)])])}const y=t(r,[["render",n]]);export{h as __pageData,y as default};
